    public void CreateOrder_AssignsUniqueId()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order1.Id);
        Assert.IsNotNull(order2.Id);
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsGreaterThan(before.AddSeconds(-1), order.CreatedAt);
        Assert.IsLessThan(DateTime.UtcNow.AddSeconds(1), order.CreatedAt);
    }

